#include <iostream>
#include <string>
#include <cstring>

template <typename T>
T findMin(T val1, T val2) {
    return (val1 < val2) ? val1 : val2;
}

int main() {
    std::cout << findMin(10, 5) << std::endl;
    std::cout << findMin(3.14, 2.71) << std::endl;
    const char* s1 = "apple";
    const char* s2 = "banana";
    std::cout << findMin(s1, s2) << std::endl;
    std::cout << findMin(std::string("grape"), std::string("fig")) << std::endl;
    return 0;
}
